   285→// buildAlertQuery creates the LogQL to perform the requested alert query.
   286→func buildAlertQuery(query AlertQuery) (string, error) {
   287→	selectors := []string{
   288→		fmt.Sprintf(`%s=%q`, historian.LabelFrom, historian.LabelFromValueAlerts),
   289→	}
   290→
   291→	logql := fmt.Sprintf(`{%s}`, strings.Join(selectors, `,`))
   292→
   293→	// UUID filtering uses structured metadata.
   294→	if query.Uuid != nil && *query.Uuid != "" {
   295→		logql += fmt.Sprintf(` | uuid = %q`, *query.Uuid)
   296→	}
   297→
   298→	logql += ` | json`
   299→
   300→	return logql, nil
   301→}
